  ('pukao-acfc4025-moex-00072', 'pukao-acfc4025', 'pukao-acfc4025-moex-113-156cbda0', 'sub-pukao-acfc4025-01', NULL, 'single_choice', '兩個長度為2的數列皆是由小到大排列，若要合併（Merge）兩個數列，且確保使得合併後的數列也能由 小到大排列，則合併過程平均要進行幾次數字比較？', '["2", "3", "8/3", "17/6"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:40+00:00", "source_pdf_sha1": "9efb7247b3e1", "answer_pdf_sha1": "3ae533baf445", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "453", "s": "2604", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "電子工程"}'::jsonb, NULL),
